import React, { useState } from "react";
import { motion } from "framer-motion";

export default function Portfolio() {
  const [darkMode, setDarkMode] = useState(true);
  const [expandedWork, setExpandedWork] = useState(null);

  const workExperience = [
    {
      id: 1,
      company: "Tapay",
      role: "Software Engineering Intern",
      period: "May 2025 - Present",
      location: "Remote",
      description: "Built and maintained Tapay's NFC-based payment dashboard using React, Next.js, and TailwindCSS, enabling secure real-time transaction tracking and billing. Developed backend APIs with Node.js, Express, and PostgreSQL to manage user accounts, billing logic, and transaction logs across 1K+ merchants. Containerized services with Docker and deployed scalable infrastructure on AWS, improving uptime and deployment speed by 30%.",
      logo: "/logos/Tapay.png",
      link: "https://tapay.com/"
    },
    {
      id: 2,
      company: "Whitman College Computer Science Department",
      role: "Research Assistant Internship",
      period: "Jun 2025 - Present",
      location: "Walla Walla, WA",
      description: "Built a machine learning model to classify internal responses to everyday sounds, achieving 60% accuracy to aid sonic interaction research. Created a seasonal sound journaling app with an AI chatbot, increasing user engagement with environmental reflection by 40%. Facilitated workshops on sound analysis and prototype development, guiding 10+ participants in exploring audio-based HCI tools.",
      logo: "/logos/whitman.png",
      link: "https://whitman.edu/"
    },
    {
      id: 3,
      company: "Whitman Health and Counseling Center",
      role: "Data Intern",
      period: "Jul 2025 - Present",
      location: "Walla Walla, WA", 
      description: "Built and optimized automated ETL pipelines using Python and SQL to process 50,000+ health records, ensuring 99% data accuracy and integrity. Collaborated with health administrators to analyze outreach trends and created dashboards in Tableau that improved student care targeting by 35%.",
      logo: "/logos/whitman.png",
      link: "https://whitman.edu/"
    },
    {
      id: 4,
      company: "HeadStarter AI Fellowship",
      role: "Software Engineering Fellow",
      period: "May 2024 - Aug 2024",
      location: "San Francisco, California",
      description: "Built an NLP pipeline with Python and Hugging Face Transformers that converted 10 K+ pages into flashcards, reducing manual study prep time by 80%. Integrated Stripe checkout and Firebase Auth for payments and user management, leading to a 20% increase in premium conversions in the first month. Implemented Node.js + Express REST endpoints with Redis caching that delivered flashcards, cutting API latency by 15% for 1.5 K weekly users.",
      logo: "/logos/Headstarter.jpg",
      link: "https://headstarter.co/"
    }
  ];

  const education = [
    {
      id: 1,
      institution: "St. Olaf College",
      degree: "Bachelor of Science, Computer Science, Statistics and Data Science",
      period: "2025 - 2028",
      location: "Northfield, MN",
      description: "Transferred from Whitman College. Coursework: Data Structure and Algorithm, Calculus 1, Intro to Data Science, Computational Exercises, Intro to Human-Centered Design, Software Design, Linear Algebra",
      logo: "/logos/olaf.png",
      link: "https://wp.stolaf.edu/"
    },
    {
      id: 2,
      institution: "Whitman College",
      degree: "Bachelor of Science, Computer Science, Statistics and Data Science",
      period: "2024 - 2025",
      location: "Walla Walla, WA",
      description: "First year before transferring to St. Olaf College. Strong foundation in computer science and data science fundamentals.",
      logo: "/logos/whitman.png",
      link: "https://whitman.edu/"
    }
  ];

  const projects = [
    {
      title: "Fertilizer Recommendation System",
      description: "Built a LightGBM-based multiclass classification model in Python to recommend the top 3 fertilizers for various soil, crop, and weather conditions. Implemented a full ML pipeline including label encoding, one-hot encoding, column alignment, and 5-fold cross-validation. Utilized: Python, Pandas, NumPy, LightGBM, Scikit-learn, Google Colab, GitHub",
      tech: ["Python", "LightGBM", "Pandas", "NumPy", "Scikit-learn", "Google Colab"],
      link: "https://github.com/Keysej",
      period: "Apr 2025",
      location: "Remote"
    },
    {
      title: "Native Plants AI Support",
      description: "Developed a GenAI-powered assistant for the Walla Walla Native Plant Society using Next.js, OpenAI API, JavaScript, and MUI to answer gardening questions and educate plant enthusiasts in real-time. Integrated local plant guides and deployed to Vercel, increasing access to drought-tolerant and region-specific plant info by 55%.",
      tech: ["Next.js", "OpenAI API", "JavaScript", "MUI", "Vercel"],
      link: "https://walla-walla-native-plant-support.vercel.app/",
      period: "Apr 2025 - Apr 2025",
      location: "Walla Walla, WA"
    },
    {
      title: "AI Rate My Professor",
      description: "Built a RAG-based AI assistant to rate professors, combining retrieval and generative AI for more informed ratings. Utilized Next.js, React, Pinecone, OpenAI, JavaScript, and MUI components.",
      tech: ["Next.js", "React", "Pinecone", "OpenAI", "JavaScript", "MUI"],
      link: "https://github.com/Keysej",
      period: "Jun 2024 - Aug 2024",
      location: "Remote"
    }
  ];

  const skills = [
    "Python", "C++", "JavaScript", "Next.js", "TypeScript", "TensorFlow", "PyTorch", 
    "Hugging Face", "Stripe API", "MongoDB", "SQL", "Firebase", "Pinecone", "BigQuery", 
    "Streamlit", "Mediapipe", "Tableau"
  ];

  const hackathons = [
    {
      id: 1,
      name: "Whitman CodeCraft Hackathon 2024",
      date: "April 20 - 21st, 2024",
      location: "Walla Walla, Washington",
      description: "Developed TranslateAI, a mobile application that supports translation across more than 50 languages using advanced machine learning algorithms. The application provides various translation modes including text-to-text, speech-to-speech, text-to-speech, speech-to-text, and audio-to-text, aiming to break language barriers by providing real-time, context-aware translations to users.",
      logo: "/logos/whitman.png",
      initial: "W"
    },
    {
      id: 2,
      name: "CodePath x AmazonNext Design Challenge",
      date: "May 2025",
      location: "Virtual Event",
      description: "Participated in the CodePath x AmazonNext Design Challenge, collaborating with a team to create innovative design solutions and present them to industry professionals. Focused on user experience design and creating impactful digital solutions.",
      logo: "/logos/Amazon Next.png",
      initial: "C"
    },
    {
      id: 3,
      name: "Kaggle Playground Series Competition",
      date: "Ongoing",
      location: "Online",
      description: "Actively participating in Kaggle machine learning competitions, focusing on data science challenges and predictive modeling. Continuously improving skills in data preprocessing, feature engineering, and model optimization through competitive machine learning.",
      logo: "/logos/kaggle.svg",
      initial: "K"
    }
  ];



  return (
    <main className={`${darkMode ? "bg-black text-white" : "bg-white text-black"} font-sans min-h-screen transition-colors duration-500`}>
      <div className="max-w-2xl mx-auto py-12 sm:py-24 px-6">
        {/* Theme Toggle */}
        <div className="flex justify-end mb-8">
          <button 
            onClick={() => setDarkMode(!darkMode)} 
            className="inline-flex items-center justify-center whitespace-nowrap text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring disabled:pointer-events-none disabled:opacity-50 hover:bg-accent hover:text-accent-foreground h-9 w-9 rounded-full px-2"
          >
            {darkMode ? "☀️" : "🌙"}
          </button>
        </div>

        {/* Hero Section */}
        <section id="hero" className="mb-16">
          <div className="mx-auto w-full max-w-2xl space-y-8">
            <div className="gap-2 flex justify-between">
              <div className="flex-col flex flex-1 space-y-1.5">
                <div className="flex">
                  <motion.span 
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    className="inline-block text-3xl font-bold tracking-tighter sm:text-5xl xl:text-6xl/none"
                  >
                    Hi, I'm Jimale 👋
                  </motion.span>
                </div>
                <div className="flex">
                  <motion.span 
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.2 }}
                    className="inline-block max-w-[600px] md:text-xl"
                  >
                    Computer Science student at St. Olaf College with expertise in machine learning, data science, and full-stack development. Passionate about creating innovative solutions that make a real impact.
                  </motion.span>
                </div>
                <div className="flex mt-2">
                  <motion.span 
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.3 }}
                    className="inline-block text-sm text-gray-400"
                  >
                    Northfield, MN 55057 | +1(509)209-3412 | keyse1@stolaf.edu
                  </motion.span>
                </div>
              </div>
              <div>
                <motion.span 
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ delay: 0.4 }}
                  className="relative flex shrink-0 overflow-hidden rounded-full size-28 border"
                >
                  <img 
                    src="/logos/jimale.jpg" 
                    alt="Jimale Keyse profile"
                    className="flex h-full w-full items-center justify-center rounded-full object-cover"
                    onError={(e) => {
                      e.target.style.display = 'none';
                      e.target.nextSibling.style.display = 'flex';
                    }}
                  />
                  <span className="flex h-full w-full items-center justify-center rounded-full bg-muted" style={{display: 'none'}}>JK</span>
                </motion.span>
              </div>
            </div>
          </div>
        </section>

        {/* About Section */}
        <section id="about" className="mb-16">
          <motion.div 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.6 }}
          >
            <h2 className="text-xl font-bold mb-4">About</h2>
          </motion.div>
          <motion.div 
            initial={{ opacity: 0, y: 20 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: 0.8 }}
          >
            <div className="prose max-w-full text-pretty font-sans text-sm text-muted-foreground dark:prose-invert">
              <p>
                I'm a Computer Science student at St. Olaf College with a strong foundation in machine learning, data science, and full-stack development. My experience spans from building NFC-based payment systems to developing AI-powered applications that solve real-world problems. I'm passionate about leveraging technology to create innovative solutions that make a meaningful impact.
              </p>
            </div>
          </motion.div>
        </section>

        {/* Work Experience Section */}
        <section id="work" className="mb-16">
          <div className="flex min-h-0 flex-col gap-y-3">
            <motion.div 
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ delay: 1.6 }}
            >
              <h2 className="text-xl font-bold">Work Experience</h2>
            </motion.div>

            {workExperience.map((work, index) => (
              <motion.div 
                key={work.id}
                initial={{ opacity: 0, y: 20 }}
                animate={{ opacity: 1, y: 0 }}
                transition={{ delay: 1.8 + index * 0.1 }}
              >
                <a 
                  className="block cursor-pointer" 
                  href={work.link}
                  onClick={(e) => {
                    e.preventDefault();
                    setExpandedWork(expandedWork === work.id ? null : work.id);
                  }}
                >
                  <div className="rounded-lg bg-card text-card-foreground flex hover:bg-gray-800 transition-colors">
                    <div className="flex-none">
                      <span className="relative flex shrink-0 overflow-hidden rounded-full border size-12 m-auto bg-muted-background dark:bg-foreground">
                        <img 
